      "keystrokes": "python3 - <<'PY'\nfrom mailman.core.initialize import initialize\nfrom mailman.interfaces.domain import IDomainManager\nfrom mailman.interfaces.listmanager import IListManager\nfrom mailman.interfaces.mailinglist import SubscriptionPolicy\ntry:\n    from mailman.interfaces.mailinglist import UnsubscriptionPolicy\nexcept Exception:\n    UnsubscriptionPolicy = None\nfrom zope.component import getUtility\n\ncfg = '/etc/mailman3/mailman.cfg'\ninitialize(cfg)\n\ndm = getUtility(IDomainManager)\ndomain = dm.get('local.edu')\nif domain is None:\n    domain = dm.add('local.edu')\n    print('Created domain local.edu')\nelse:\n    print('Domain local.edu already exists')\n\nlm = getUtility(IListManager)\nmlist = lm.get('reading-group@local.edu')\nif mlist is None:\n    mlist = lm.create('reading-group', 'local.edu')\n    print('Created list reading-group@local.edu')\nelse:\n    print('List reading-group@local.edu already exists')\n\n# Set subscription policy to open (no owner approval). Confirmation remains required by default.\nmlist.subscription_policy = SubscriptionPolicy.open\nprint('Set subscription_policy to open')\n\nif UnsubscriptionPolicy is not None:\n    try:\n        mlist.unsubscription_policy = UnsubscriptionPolicy.confirm\n        print('Set unsubscription_policy to confirm')\n    except Exception as e:\n        print('Could not set unsubscription_policy:', e)\nPY\n",
